-- =============================================================================
-- storefront_seed.sql — Dữ liệu mẫu tiếng Việt cho website khách hàng.
-- Chạy được nhiều lần (idempotent theo slug). Chỉ ghi vào bảng storefront_*.
-- KHÔNG đụng tới dữ liệu dashboard. product_type_code trỏ tới product_types.code
-- đã có sẵn trong 00_reference.sql của dashboard.
-- =============================================================================

insert into storefront_products (
  slug, sku, name, product_type_code,
  short_description, long_description,
  image_url, gallery,
  pricing_type, price_from, price_unit,
  pricing, options,
  lead_time, file_guide, faq,
  needs_quote, allow_instant_payment, requires_deposit, deposit_amount,
  category, service_type, is_featured, is_published, sort_order,
  seo_title, seo_description
) values
  ('tem-nhua-sua', 'TEM-SUA', 'Tem nhựa sữa', 'TEM_NHAN', 'Tem decal nhựa sữa trắng đục, bám dính tốt, chống nước — dán chai lọ, hũ mỹ phẩm, thực phẩm.', 'Tem nhựa sữa (PP sữa) là lựa chọn phổ biến nhất cho nhãn sản phẩm cần chống nước và chống dầu. Bề mặt trắng đục lên màu chuẩn, mực in không lem khi gặp ẩm. Chúng tôi in offset UV cho số lượng lớn và in kỹ thuật số cho combo nhỏ, bế thành từng con theo khuôn tròn, vuông hoặc bo góc.

Phù hợp: hũ kem, chai serum, lọ tinh dầu, hộp thực phẩm, nhãn niêm phong.', '/products/tem-nhua-sua.svg', '["/products/tem-nhua-sua.svg", "/products/tem-nhua-sua-2.svg"]'::jsonb, 'FIXED_PRICE', 180000, 'combo 100 tem', '{"mode": "per_pack", "roundTo": 1000}'::jsonb, '[{"key": "pack", "label": "Số lượng", "type": "select", "required": true, "values": [{"value": "100", "label": "100 tem", "flatPrice": 180000, "quantity": 100}, {"value": "500", "label": "500 tem", "flatPrice": 520000, "quantity": 500}, {"value": "1000", "label": "1.000 tem", "flatPrice": 850000, "quantity": 1000}, {"value": "2000", "label": "2.000 tem", "flatPrice": 1450000, "quantity": 2000}]}, {"key": "shape", "label": "Hình dạng", "type": "radio", "required": true, "values": [{"value": "tron", "label": "Tròn", "priceFlat": 0}, {"value": "vuong_bo_goc", "label": "Vuông bo góc", "priceFlat": 0}, {"value": "theo_hinh", "label": "Bế theo hình riêng", "priceFlat": 150000}]}, {"key": "finishing", "label": "Gia công", "type": "radio", "required": false, "values": [{"value": "khong", "label": "Không cán màng", "priceFlat": 0}, {"value": "can_mo", "label": "Cán màng mờ", "priceFlat": 40000}, {"value": "can_bong", "label": "Cán màng bóng", "priceFlat": 40000}]}]'::jsonb, '2 – 3 ngày làm việc', 'File PDF hoặc AI, hệ màu CMYK, độ phân giải 300dpi. Chừa tràn lề 2mm mỗi cạnh và đặt chữ cách mép bế tối thiểu 3mm.', '[{"q": "Tem có dán được lên hũ đông lạnh không?", "a": "Được. Keo nhựa sữa vẫn bám ở nhiệt độ thấp, nhưng nên dán khi bề mặt khô và sạch dầu."}, {"q": "Tôi chưa có file thì sao?", "a": "Bạn gửi ý tưởng và logo, đội thiết kế sẽ dựng mẫu trước khi in."}]'::jsonb, false, true, false, null, 'tem-sticker', 'in_an', true, true, 1, 'Tem nhựa sữa — giá và đặt in online | Nhà In Trẻ', 'Tem decal nhựa sữa trắng đục, bám dính tốt, chống nước — dán chai lọ, hũ mỹ phẩm, thực phẩm.'),
  ('tem-trong-suot', 'TEM-TRONG', 'Tem trong suốt', 'TEM_NHAN', 'Tem decal trong, nhìn xuyên nền — cho chai thủy tinh, hộp nhựa trong, bao bì tối giản.', 'Tem trong suốt tạo hiệu ứng “không nhãn”: chỉ thấy hình và chữ nổi trên bề mặt sản phẩm. Với nền tối hoặc màu đậm, nên in thêm lớp mực trắng lót để màu không bị chìm — bạn chọn ngay ở tùy chọn bên dưới.

Phù hợp: chai nước, lọ thủy tinh, hộp nhựa trong, nhãn niêm phong vô hình.', '/products/tem-trong-suot.svg', '["/products/tem-trong-suot.svg", "/products/tem-trong-suot-2.svg"]'::jsonb, 'FIXED_PRICE', 210000, 'combo 100 tem', '{"mode": "per_pack", "roundTo": 1000}'::jsonb, '[{"key": "pack", "label": "Số lượng", "type": "select", "required": true, "values": [{"value": "100", "label": "100 tem", "flatPrice": 210000, "quantity": 100}, {"value": "500", "label": "500 tem", "flatPrice": 620000, "quantity": 500}, {"value": "1000", "label": "1.000 tem", "flatPrice": 990000, "quantity": 1000}]}, {"key": "white_ink", "label": "Lót mực trắng", "type": "radio", "required": true, "values": [{"value": "khong", "label": "Không lót (nền sáng)", "priceFlat": 0}, {"value": "co", "label": "Có lót mực trắng (nền tối)", "priceFlat": 120000}]}, {"key": "finishing", "label": "Gia công", "type": "radio", "required": false, "values": [{"value": "khong", "label": "Không cán màng", "priceFlat": 0}, {"value": "can_mo", "label": "Cán màng mờ", "priceFlat": 40000}, {"value": "can_bong", "label": "Cán màng bóng", "priceFlat": 40000}]}]'::jsonb, '2 – 3 ngày làm việc', 'File PDF/AI, CMYK, 300dpi. Nếu cần lót trắng, tách riêng một layer đặt tên “WHITE” cho vùng cần lót.', '[{"q": "Vì sao màu in trên tem trong nhạt hơn bản thiết kế?", "a": "Vì nền sản phẩm ánh qua lớp mực. Chọn lót mực trắng nếu bạn cần màu đúng như thiết kế."}]'::jsonb, false, true, false, null, 'tem-sticker', 'in_an', true, true, 2, 'Tem trong suốt — giá và đặt in online | Nhà In Trẻ', 'Tem decal trong, nhìn xuyên nền — cho chai thủy tinh, hộp nhựa trong, bao bì tối giản.'),
  ('sticker-be-theo-hinh', 'STK-BE', 'Sticker bế theo hình', 'STICKER', 'Sticker cắt rời đúng đường viền hình của bạn — làm quà tặng, dán laptop, trang trí đơn hàng.', 'Bế theo hình (die-cut) nghĩa là con sticker được cắt bám sát đường viền thiết kế, không còn nền vuông thừa. In trên decal PP cán màng chống xước, bóc dán dễ, không để lại keo.

Phù hợp: quà kèm đơn hàng, sticker thương hiệu, sticker sự kiện, dán bình nước và laptop.', '/products/sticker-be-theo-hinh.svg', '["/products/sticker-be-theo-hinh.svg", "/products/sticker-be-theo-hinh-2.svg"]'::jsonb, 'FIXED_PRICE', 150000, 'combo 100 con', '{"mode": "per_pack", "roundTo": 1000}'::jsonb, '[{"key": "pack", "label": "Số lượng", "type": "select", "required": true, "values": [{"value": "100", "label": "100 con", "flatPrice": 150000, "quantity": 100}, {"value": "300", "label": "300 con", "flatPrice": 380000, "quantity": 300}, {"value": "500", "label": "500 con", "flatPrice": 560000, "quantity": 500}, {"value": "1000", "label": "1.000 con", "flatPrice": 980000, "quantity": 1000}]}, {"key": "size", "label": "Kích thước con", "type": "radio", "required": true, "values": [{"value": "3cm", "label": "Cạnh dài 3cm", "priceMultiplier": 1}, {"value": "5cm", "label": "Cạnh dài 5cm", "priceMultiplier": 1.35}, {"value": "8cm", "label": "Cạnh dài 8cm", "priceMultiplier": 1.9}]}, {"key": "finishing", "label": "Bề mặt", "type": "radio", "required": false, "values": [{"value": "can_mo", "label": "Cán màng mờ", "priceFlat": 0}, {"value": "can_bong", "label": "Cán màng bóng", "priceFlat": 0}, {"value": "trong_kinh", "label": "Nền trong kính", "priceFlat": 60000}]}]'::jsonb, '3 ngày làm việc', 'File AI/PDF có đường bế vẽ bằng Spot Color đặt tên “CutContour”, hoặc PNG nền trong suốt — chúng tôi sẽ tạo đường bế cách hình 2mm.', '[{"q": "Sticker có chống nước không?", "a": "Có. Decal PP cán màng chịu được nước và cồn lau, không nên ngâm lâu."}]'::jsonb, false, true, false, null, 'tem-sticker', 'in_an', true, true, 3, 'Sticker bế theo hình — giá và đặt in online | Nhà In Trẻ', 'Sticker cắt rời đúng đường viền hình của bạn — làm quà tặng, dán laptop, trang trí đơn hàng.'),
  ('decal-kinh-mo', 'DECAL-KINH', 'Decal kính mờ', 'DECAL_KINH', 'Dán kính mờ cho mặt tiền, phòng họp, nhà tắm — cản nhìn nhưng vẫn lấy sáng.', 'Decal kính mờ (sandblast) tạo hiệu ứng kính phun cát với chi phí thấp hơn nhiều lần và có thể tháo khi đổi mặt bằng. Có thể cắt rỗng logo, dải trang trí, hoặc dán nguyên tấm.

Diện tích lớn cần đo đạc thực tế và tính chi phí thi công, nên sản phẩm này báo giá sau khi khảo sát.', '/products/decal-kinh-mo.svg', '["/products/decal-kinh-mo.svg", "/products/decal-kinh-mo-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Chất liệu", "type": "radio", "required": true, "values": [{"value": "mo_trang", "label": "Mờ trắng trơn"}, {"value": "mo_hoa_tiet", "label": "Mờ có hoa tiết"}, {"value": "mo_cat_chu", "label": "Mờ cắt rỗng chữ / logo"}]}, {"key": "finishing", "label": "Thi công", "type": "radio", "required": true, "values": [{"value": "tu_dan", "label": "Gửi hàng, tôi tự dán"}, {"value": "co_thi_cong", "label": "Cần thợ dán tại chỗ"}]}]'::jsonb, 'Khảo sát trong 24h, thi công 2 – 5 ngày', 'Gửi ảnh chụp toàn bộ mặt kính kèm số đo rộng × cao. Nếu có logo, gửi file vector AI/PDF/SVG.', '[{"q": "Dán decal có làm hỏng kính không?", "a": "Không. Khi tháo, lớp keo được xử lý bằng dung dịch chuyên dụng và không để lại vết."}]'::jsonb, true, false, false, null, 'decal', 'thi_cong', false, true, 4, 'Decal kính mờ — giá và đặt in online | Nhà In Trẻ', 'Dán kính mờ cho mặt tiền, phòng họp, nhà tắm — cản nhìn nhưng vẫn lấy sáng.'),
  ('decal-chu-cat', 'DECAL-CAT', 'Decal chữ cắt', 'DECAL_CHU_CAT', 'Chữ và logo cắt rời từ decal màu, dán trực tiếp lên kính, tường, xe — không nền.', 'Decal chữ cắt được cắt bằng máy bế từ decal màu nguyên khối, bóc bỏ phần nền, chỉ còn lại nét chữ. Vì không có nền nên chữ trông như được sơn trực tiếp lên bề mặt.

Giá phụ thuộc số nét, độ phức tạp của font và diện tích bao — nên chúng tôi xem file rồi báo giá chính xác.', '/products/decal-chu-cat.svg', '["/products/decal-chu-cat.svg", "/products/decal-chu-cat-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Màu decal", "type": "radio", "required": true, "values": [{"value": "den", "label": "Đen"}, {"value": "trang", "label": "Trắng"}, {"value": "do", "label": "Đỏ"}, {"value": "vang_kim", "label": "Vàng kim / bạc ánh kim"}]}]'::jsonb, '1 – 2 ngày làm việc', 'Bắt buộc file vector (AI, PDF, SVG) và chữ đã convert to outline. File ảnh PNG/JPG không cắt được.', '[{"q": "Chữ nhỏ nhất cắt được là bao nhiêu?", "a": "Nét chữ nên dày tối thiểu 2mm. Mảnh hơn nữa sẽ rách khi bóc dán."}]'::jsonb, true, false, false, null, 'decal', 'in_an', false, true, 5, 'Decal chữ cắt — giá và đặt in online | Nhà In Trẻ', 'Chữ và logo cắt rời từ decal màu, dán trực tiếp lên kính, tường, xe — không nền.'),
  ('bat-hiflex', 'BAT-HIFLEX', 'Bạt Hiflex', 'BAT_HIFLEX', 'Bạt in khổ lớn cho băng rôn, phông sự kiện, biển treo — tính tiền theo mét vuông.', 'Bạt Hiflex là vật liệu quen thuộc nhất cho quảng cáo ngoài trời: bền nắng mưa, giá rẻ, in được khổ rất lớn. Chúng tôi in độ phân giải cao nên nhìn gần vẫn nét, không rỗ hạt như bạt in nhanh.

Giá tính theo diện tích thực tế, tối thiểu 1m².', '/products/bat-hiflex.svg', '["/products/bat-hiflex.svg", "/products/bat-hiflex-2.svg"]'::jsonb, 'FIXED_PRICE', 90000, 'm²', '{"mode": "per_area", "base": 90000, "minAreaM2": 1, "minCharge": 90000, "roundTo": 1000, "size": {"minWidthCm": 30, "maxWidthCm": 3000, "minHeightCm": 30, "maxHeightCm": 1000}}'::jsonb, '[{"key": "material", "label": "Loại bạt", "type": "radio", "required": true, "values": [{"value": "hiflex_thuong", "label": "Hiflex thường (trong nhà)", "priceDelta": 0}, {"value": "hiflex_3m", "label": "Hiflex 3M dày (ngoài trời)", "priceDelta": 35000}, {"value": "hiflex_xuyen_den", "label": "Hiflex xuyên đèn", "priceDelta": 70000}]}, {"key": "finishing", "label": "Gia công", "type": "radio", "required": false, "values": [{"value": "cat_thanh_pham", "label": "Cắt thành phẩm", "priceFlat": 0}, {"value": "dan_bien_khoen", "label": "Dán biên + đóng khoen treo", "priceDelta": 15000}]}]'::jsonb, '1 – 2 ngày làm việc', 'File PDF/JPG, CMYK. Khổ lớn có thể thiết kế tỉ lệ 1:10 ở 300dpi. Chừa mép dán biên 3cm nếu chọn đóng khoen.', '[{"q": "Bạt dùng ngoài trời được bao lâu?", "a": "Hiflex 3M dày ngoài trời giữ màu tốt khoảng 12 – 18 tháng tùy hướng nắng."}]'::jsonb, false, true, false, null, 'in-kho-lon', 'in_an', true, true, 6, 'Bạt Hiflex — giá và đặt in online | Nhà In Trẻ', 'Bạt in khổ lớn cho băng rôn, phông sự kiện, biển treo — tính tiền theo mét vuông.'),
  ('poster-pp', 'POSTER-PP', 'Poster PP', 'POSTER_PP', 'Poster in PP cán màng, màu tươi và sắc nét — treo trong cửa hàng, quán cà phê, sự kiện.', 'Giấy PP có lớp phủ giúp mực bám đều, lên màu tươi hơn hẳn giấy thường, và cán màng xong thì không sợ ẩm hay xước. Đây là lựa chọn tiêu chuẩn cho poster khuyến mãi, menu treo tường và ảnh trưng bày.

Giá theo diện tích, tối thiểu 0,25m² (cỡ A2).', '/products/poster-pp.svg', '["/products/poster-pp.svg", "/products/poster-pp-2.svg"]'::jsonb, 'FIXED_PRICE', 110000, 'm²', '{"mode": "per_area", "base": 110000, "minAreaM2": 0.25, "minCharge": 40000, "roundTo": 1000, "size": {"minWidthCm": 20, "maxWidthCm": 150, "minHeightCm": 20, "maxHeightCm": 300}}'::jsonb, '[{"key": "finishing", "label": "Cán màng", "type": "radio", "required": true, "values": [{"value": "khong", "label": "Không cán", "priceDelta": 0}, {"value": "can_mo", "label": "Cán màng mờ", "priceDelta": 25000}, {"value": "can_bong", "label": "Cán màng bóng", "priceDelta": 25000}]}, {"key": "backing", "label": "Bồi nền", "type": "radio", "required": false, "values": [{"value": "khong", "label": "Không bồi", "priceDelta": 0}, {"value": "formex", "label": "Bồi formex 3mm", "priceDelta": 90000}, {"value": "alu", "label": "Bồi tấm alu", "priceDelta": 180000}]}]'::jsonb, '1 ngày làm việc', 'File PDF/JPG, CMYK, 150 – 300dpi ở kích thước thật. Chừa tràn lề 3mm.', '[{"q": "Poster A0 là bao nhiêu?", "a": "A0 = 84,1 × 118,9cm, tương đương 1m². Bạn nhập đúng số đo này ở phần kích thước."}]'::jsonb, false, true, false, null, 'in-kho-lon', 'in_an', true, true, 7, 'Poster PP — giá và đặt in online | Nhà In Trẻ', 'Poster in PP cán màng, màu tươi và sắc nét — treo trong cửa hàng, quán cà phê, sự kiện.'),
  ('standee-chu-x', 'STD-X', 'Standee chữ X', 'STANDEE_X', 'Standee khung chữ X nhẹ, lắp trong một phút — giá rẻ nhất để có một tấm đứng ở cửa.', 'Khung chữ X gấp gọn, nhẹ, chỉ cần treo bạt vào bốn góc là dựng xong. Rẻ và tiện, phù hợp khi bạn cần nhiều điểm trưng bày hoặc thay nội dung liên tục.

Giá đã gồm khung và bạt in.', '/products/standee-chu-x.svg', '["/products/standee-chu-x.svg", "/products/standee-chu-x-2.svg"]'::jsonb, 'FIXED_PRICE', 190000, 'bộ', '{"mode": "per_item", "base": 190000, "roundTo": 1000, "tiers": [{"minQty": 5, "price": 175000}, {"minQty": 10, "price": 160000}]}'::jsonb, '[{"key": "size", "label": "Kích thước", "type": "radio", "required": true, "values": [{"value": "60x160", "label": "60 × 160cm", "priceMultiplier": 1, "width": 60, "height": 160}, {"value": "80x180", "label": "80 × 180cm", "priceMultiplier": 1.25, "width": 80, "height": 180}]}]'::jsonb, '1 ngày làm việc', 'Thiết kế đúng tỉ lệ khung. Chừa vùng an toàn 5cm phía trên và dưới vì bốn góc sẽ bị khung che.', '[{"q": "Đổi nội dung có phải mua lại khung không?", "a": "Không. Bạn chỉ cần in bạt mới và giữ lại khung."}]'::jsonb, false, true, false, null, 'in-kho-lon', 'in_an', false, true, 8, 'Standee chữ X — giá và đặt in online | Nhà In Trẻ', 'Standee khung chữ X nhẹ, lắp trong một phút — giá rẻ nhất để có một tấm đứng ở cửa.'),
  ('standee-cuon', 'STD-CUON', 'Standee cuốn', 'STANDEE_CUON', 'Standee cuốn nhôm, tự cuộn vào hộp khi thu — dùng cho hội thảo, gian hàng, sảnh đón khách.', 'Bản in cuộn vào hộp nhôm nên không nhăn, không gãy gập khi di chuyển. Đây là loại standee trông chuyên nghiệp nhất và bền nhất trong ba loại phổ biến.

Giá đã gồm hộp nhôm, thanh chống và túi đựng.', '/products/standee-cuon.svg', '["/products/standee-cuon.svg", "/products/standee-cuon-2.svg"]'::jsonb, 'FIXED_PRICE', 450000, 'bộ', '{"mode": "per_item", "base": 450000, "roundTo": 1000, "tiers": [{"minQty": 3, "price": 420000}, {"minQty": 10, "price": 390000}]}'::jsonb, '[{"key": "size", "label": "Kích thước", "type": "radio", "required": true, "values": [{"value": "80x200", "label": "80 × 200cm", "priceMultiplier": 1, "width": 80, "height": 200}, {"value": "85x200", "label": "85 × 200cm", "priceMultiplier": 1.1, "width": 85, "height": 200}]}, {"key": "material", "label": "Chất liệu in", "type": "radio", "required": true, "values": [{"value": "pp_can_mo", "label": "PP cán mờ", "priceDelta": 0}, {"value": "pp_chong_cong", "label": "PP chống cong (dày hơn)", "priceDelta": 80000}]}]'::jsonb, '2 ngày làm việc', 'Thiết kế đúng kích thước thật, chừa 12cm phía dưới cho phần chân hộp. Nội dung quan trọng nên nằm trên 60cm tính từ đáy.', '[{"q": "Standee cuốn có bị cong mép không?", "a": "Bản PP thường có thể hơi cong sau vài tháng. Chọn PP chống cong nếu bạn dùng lâu dài."}]'::jsonb, false, true, false, null, 'in-kho-lon', 'in_an', true, true, 9, 'Standee cuốn — giá và đặt in online | Nhà In Trẻ', 'Standee cuốn nhôm, tự cuộn vào hộp khi thu — dùng cho hội thảo, gian hàng, sảnh đón khách.'),
  ('menu', 'MENU', 'Menu', 'MENU', 'Menu quán cà phê, nhà hàng — in giấy dày cán màng, chống dầu và nước đổ.', 'Menu là thứ khách cầm nhiều nhất trong quán, nên chúng tôi mặc định in giấy Couche 300gsm và cán màng hai mặt. Có thể làm dạng tờ rời, gấp đôi, hoặc ép plastic cứng.

