  ('danh-thiep', 'DT', 'Danh thiếp', 'DANH_THIEP', 'Danh thiếp giấy mỹ thuật, cán mờ, bo góc — đặt online, thanh toán ngay, nhận sau 2 ngày.', 'Kích thước tiêu chuẩn 9 × 5,5cm, in hai mặt. Bạn chọn combo, chọn giấy, tải file lên và thanh toán — không cần chờ báo giá.

Giấy Couche 300gsm là mặc định. Giấy mỹ thuật cho cảm giác dày và nhám hơn, hợp với thương hiệu tối giản.', '/products/danh-thiep.svg', '["/products/danh-thiep.svg", "/products/danh-thiep-2.svg"]'::jsonb, 'FIXED_PRICE', 120000, 'hộp 100 tấm', '{"mode": "per_pack", "roundTo": 1000}'::jsonb, '[{"key": "pack", "label": "Số lượng", "type": "select", "required": true, "values": [{"value": "100", "label": "1 hộp – 100 tấm", "flatPrice": 120000, "quantity": 100}, {"value": "500", "label": "5 hộp – 500 tấm", "flatPrice": 420000, "quantity": 500}, {"value": "1000", "label": "10 hộp – 1.000 tấm", "flatPrice": 690000, "quantity": 1000}]}, {"key": "material", "label": "Chất liệu giấy", "type": "radio", "required": true, "values": [{"value": "couche_300", "label": "Couche 300gsm", "priceMultiplier": 1}, {"value": "my_thuat", "label": "Giấy mỹ thuật 320gsm", "priceMultiplier": 1.45}, {"value": "kraft", "label": "Giấy kraft 300gsm", "priceMultiplier": 1.3}]}, {"key": "finishing", "label": "Gia công", "type": "radio", "required": false, "values": [{"value": "khong", "label": "Không", "priceFlat": 0}, {"value": "can_mo", "label": "Cán màng mờ 2 mặt", "priceFlat": 40000}, {"value": "bo_goc", "label": "Cán mờ + bo góc tròn", "priceFlat": 70000}]}]'::jsonb, '2 ngày làm việc', 'File PDF 9 × 5,5cm, CMYK, 300dpi, tràn lề 2mm, chữ cách mép 4mm. Gửi cả hai mặt trong một file 2 trang.', '[{"q": "In một mặt có rẻ hơn không?", "a": "Không đáng kể, nên chúng tôi để giá chung cho cả hai mặt."}, {"q": "Tôi muốn ép kim?", "a": "Ép kim cần báo giá riêng — bạn gửi yêu cầu ở trang Gửi file in nhé."}]'::jsonb, false, true, false, null, 'an-pham', 'in_an', true, true, 11, 'Danh thiếp — giá và đặt in online | Nhà In Trẻ', 'Danh thiếp giấy mỹ thuật, cán mờ, bo góc — đặt online, thanh toán ngay, nhận sau 2 ngày.'),
  ('voucher', 'VOUCHER', 'Voucher', 'VOUCHER', 'Voucher giảm giá, thẻ tích điểm, phiếu quà tặng — có thể đánh số nhảy từng tờ.', 'Voucher in trên giấy Couche 300gsm, cán màng để không nhàu trong ví khách. Cần chống dùng lại nhiều lần thì chọn đánh số nhảy — mỗi tờ một số riêng, chúng tôi xử lý phần dữ liệu số.

Kích thước mặc định 9 × 5,5cm hoặc 14,8 × 5,2cm.', '/products/voucher.svg', '["/products/voucher.svg", "/products/voucher-2.svg"]'::jsonb, 'FIXED_PRICE', 180000, 'combo 100 tờ', '{"mode": "per_pack", "roundTo": 1000}'::jsonb, '[{"key": "pack", "label": "Số lượng", "type": "select", "required": true, "values": [{"value": "100", "label": "100 tờ", "flatPrice": 180000, "quantity": 100}, {"value": "500", "label": "500 tờ", "flatPrice": 560000, "quantity": 500}, {"value": "1000", "label": "1.000 tờ", "flatPrice": 920000, "quantity": 1000}]}, {"key": "numbering", "label": "Đánh số nhảy", "type": "radio", "required": true, "values": [{"value": "khong", "label": "Không đánh số", "priceFlat": 0}, {"value": "co", "label": "Có đánh số nhảy", "priceFlat": 150000}]}, {"key": "finishing", "label": "Gia công", "type": "radio", "required": false, "values": [{"value": "can_mo", "label": "Cán màng mờ", "priceFlat": 0}, {"value": "rang_cua", "label": "Cán mờ + răng cưa xé", "priceFlat": 80000}]}]'::jsonb, '2 – 3 ngày làm việc', 'File PDF, CMYK, 300dpi. Nếu đánh số nhảy, chừa một ô trống và ghi rõ dải số bắt đầu – kết thúc trong ghi chú.', '[{"q": "Đánh số nhảy bắt đầu từ đâu?", "a": "Bạn ghi dải số mong muốn trong ghi chú, ví dụ 0001 – 1000."}]'::jsonb, false, true, false, null, 'an-pham', 'in_an', false, true, 12, 'Voucher — giá và đặt in online | Nhà In Trẻ', 'Voucher giảm giá, thẻ tích điểm, phiếu quà tặng — có thể đánh số nhảy từng tờ.'),
  ('backdrop', 'BACKDROP', 'Backdrop', 'BACKDROP', 'Backdrop sự kiện, lễ khai trương, chụp ảnh — in bạt khổ lớn kèm khung và dựng tại chỗ.', 'Backdrop gồm ba phần: bản in, khung, và công dựng. Vì khung và công phụ thuộc mặt bằng, chúng tôi nhận đặt cọc để giữ lịch sản xuất, sau đó khảo sát và báo giá phần còn lại.

Nhận dựng trong ngày cho sự kiện gấp nếu bạn đặt trước 48 giờ.', '/products/backdrop.svg', '["/products/backdrop.svg", "/products/backdrop-2.svg"]'::jsonb, 'DEPOSIT_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Loại khung", "type": "radio", "required": true, "values": [{"value": "khung_truss", "label": "Khung truss nhôm"}, {"value": "khung_sat", "label": "Khung sắt hộp"}, {"value": "khung_gap", "label": "Khung gấp di động"}]}, {"key": "finishing", "label": "Thi công", "type": "radio", "required": true, "values": [{"value": "co_dung", "label": "Cần dựng tại địa điểm"}, {"value": "chi_in", "label": "Chỉ in bạt, tôi tự dựng"}]}]'::jsonb, 'Dựng trong 1 – 3 ngày sau khi chốt', 'Gửi file thiết kế PDF tỉ lệ 1:10 ở 300dpi, kèm số đo rộng × cao và ảnh chụp vị trí dựng.', '[{"q": "Đặt cọc rồi hủy thì sao?", "a": "Hủy trước khi in, chúng tôi hoàn cọc trong 3 ngày làm việc."}]'::jsonb, true, false, true, 500000, 'in-kho-lon', 'thi_cong', false, true, 13, 'Backdrop — giá và đặt in online | Nhà In Trẻ', 'Backdrop sự kiện, lễ khai trương, chụp ảnh — in bạt khổ lớn kèm khung và dựng tại chỗ.'),
  ('bien-cong-ty', 'BIEN-CT', 'Biển công ty', 'BIEN_CONG_TY', 'Biển tên công ty đặt sảnh, cửa văn phòng — mica, inox hoặc alu, kèm lắp đặt.', 'Biển công ty làm theo nhận diện của bạn: nền alu hoặc mica, chữ nổi inox hoặc mica cắt CNC. Chúng tôi đo tại chỗ, dựng bản vẽ 3D để bạn duyệt trước khi cắt.

Đặt cọc để chốt lịch khảo sát và giữ suất sản xuất; phần còn lại thanh toán sau khi bạn duyệt bản vẽ.', '/products/bien-cong-ty.svg', '["/products/bien-cong-ty.svg", "/products/bien-cong-ty-2.svg"]'::jsonb, 'DEPOSIT_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Chất liệu nền", "type": "radio", "required": true, "values": [{"value": "mica", "label": "Mica"}, {"value": "alu", "label": "Alu"}, {"value": "inox_xuoc", "label": "Inox xước"}]}, {"key": "finishing", "label": "Kiểu chữ", "type": "radio", "required": true, "values": [{"value": "chu_noi", "label": "Chữ nổi"}, {"value": "chu_khac", "label": "Chữ khắc chìm"}, {"value": "in_uv", "label": "In UV trực tiếp"}]}]'::jsonb, '5 – 7 ngày làm việc', 'Gửi logo dạng vector (AI/PDF/SVG) và ảnh chụp vị trí treo. Nếu chỉ có ảnh logo, chúng tôi vector hóa lại.', '[{"q": "Có bản vẽ trước khi làm không?", "a": "Có. Chúng tôi gửi ảnh mô phỏng đặt trên ảnh thật của mặt bằng để bạn duyệt."}]'::jsonb, true, false, true, 1000000, 'bien-hieu', 'thi_cong', false, true, 14, 'Biển công ty — giá và đặt in online | Nhà In Trẻ', 'Biển tên công ty đặt sảnh, cửa văn phòng — mica, inox hoặc alu, kèm lắp đặt.'),
  ('bien-alu', 'BIEN-ALU', 'Biển Alu', 'BIEN_ALU', 'Biển hiệu nền alu chữ nổi — bền, phẳng, chịu mưa nắng, dùng cho mặt tiền cửa hàng.', 'Alu (nhôm nhựa composite) là nền biển phổ biến nhất cho mặt tiền: phẳng đẹp, không cong vênh, chịu thời tiết tốt. Ghép với chữ nổi mica hoặc inox và đèn LED hắt là thành bộ biển hoàn chỉnh.

Giá phụ thuộc diện tích, số chữ, loại đèn và độ khó khi lắp — cần khảo sát để báo đúng.', '/products/bien-alu.svg', '["/products/bien-alu.svg", "/products/bien-alu-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Màu alu", "type": "radio", "required": true, "values": [{"value": "trang", "label": "Alu trắng"}, {"value": "den", "label": "Alu đen"}, {"value": "xuoc_bac", "label": "Alu xước bạc"}, {"value": "khac", "label": "Màu khác theo nhận diện"}]}, {"key": "finishing", "label": "Đèn", "type": "radio", "required": false, "values": [{"value": "khong", "label": "Không đèn"}, {"value": "led_hat", "label": "LED hắt sáng chữ"}, {"value": "led_vien", "label": "LED viền biển"}]}]'::jsonb, '5 – 7 ngày làm việc', 'Gửi ảnh chụp thẳng mặt tiền (đứng đối diện, lấy trọn chiều ngang) kèm số đo rộng × cao và file logo vector.', '[{"q": "Có xin phép treo biển giúp không?", "a": "Chúng tôi hướng dẫn hồ sơ và kích thước theo quy định, phần nộp hồ sơ do bên bạn thực hiện."}]'::jsonb, true, false, false, null, 'bien-hieu', 'thi_cong', false, true, 15, 'Biển Alu — giá và đặt in online | Nhà In Trẻ', 'Biển hiệu nền alu chữ nổi — bền, phẳng, chịu mưa nắng, dùng cho mặt tiền cửa hàng.'),
  ('chu-mica', 'CHU-MICA', 'Chữ mica', 'CHU_MICA', 'Chữ nổi mica cắt CNC, gắn chân hoặc gắn thẳng — nét sắc, nhiều màu, gắn LED được.', 'Chữ mica cắt CNC cho cạnh nhẵn và nét sắc kể cả với font mảnh. Có thể để mica màu nguyên khối, dán decal, hoặc làm mica hút nổi gắn LED bên trong.

Báo giá theo chiều cao chữ, độ dày mica và số ký tự.', '/products/chu-mica.svg', '["/products/chu-mica.svg", "/products/chu-mica-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Độ dày mica", "type": "radio", "required": true, "values": [{"value": "3mm", "label": "3mm"}, {"value": "5mm", "label": "5mm"}, {"value": "10mm", "label": "10mm"}, {"value": "hut_noi", "label": "Mica hút nổi gắn LED"}]}, {"key": "finishing", "label": "Cách gắn", "type": "radio", "required": true, "values": [{"value": "gan_thang", "label": "Gắn thẳng vào nền"}, {"value": "gan_chan", "label": "Gắn chân đôn nổi khỏi tường"}]}]'::jsonb, '3 – 5 ngày làm việc', 'Bắt buộc file vector, chữ đã convert to outline. Ghi rõ chiều cao chữ hoa mong muốn (cm).', '[{"q": "Chữ mảnh có cắt được không?", "a": "Nét nên dày tối thiểu 8mm với mica 5mm, nếu mảnh hơn chữ dễ gãy khi vận chuyển."}]'::jsonb, true, false, false, null, 'bien-hieu', 'thi_cong', false, true, 16, 'Chữ mica — giá và đặt in online | Nhà In Trẻ', 'Chữ nổi mica cắt CNC, gắn chân hoặc gắn thẳng — nét sắc, nhiều màu, gắn LED được.'),
  ('bien-led', 'BIEN-LED', 'Biển LED', 'BIEN_LED', 'Biển LED ma trận chạy chữ hoặc biển chữ nổi gắn LED — sáng rõ vào buổi tối.', 'Hai kiểu phổ biến: biển LED ma trận chạy chữ (module LED, đổi nội dung bằng điện thoại) và biển chữ nổi gắn LED (sang hơn, dùng cho thương hiệu). Chúng tôi tư vấn theo mặt tiền và ngân sách của bạn.

Giá gồm module, nguồn, khung và công lắp — cần khảo sát điện và vị trí treo.', '/products/bien-led.svg', '["/products/bien-led.svg", "/products/bien-led-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Kiểu biển", "type": "radio", "required": true, "values": [{"value": "ma_tran", "label": "LED ma trận chạy chữ"}, {"value": "chu_noi_led", "label": "Chữ nổi gắn LED"}, {"value": "led_am", "label": "LED âm bản (hắt ngược)"}]}, {"key": "finishing", "label": "Màu LED", "type": "radio", "required": false, "values": [{"value": "trang", "label": "Trắng"}, {"value": "vang", "label": "Vàng ấm"}, {"value": "full_color", "label": "Full color"}]}]'::jsonb, '7 – 10 ngày làm việc', 'Gửi ảnh mặt tiền, số đo rộng × cao, vị trí ổ điện gần nhất và file logo vector nếu có.', '[{"q": "Bảo hành bao lâu?", "a": "12 tháng cho module LED và nguồn, đổi mới nếu lỗi nhà sản xuất."}]'::jsonb, true, false, false, null, 'bien-hieu', 'thi_cong', false, true, 17, 'Biển LED — giá và đặt in online | Nhà In Trẻ', 'Biển LED ma trận chạy chữ hoặc biển chữ nổi gắn LED — sáng rõ vào buổi tối.'),
  ('hop-den', 'HOP-DEN', 'Hộp đèn', 'HOP_DEN', 'Hộp đèn mica hoặc bạt xuyên đèn, một mặt hoặc hai mặt — treo vuông góc mặt tiền, nhìn thấy từ xa.', 'Hộp đèn giúp cửa hàng của bạn được nhìn thấy từ đầu phố vì nó nhô ra khỏi mặt tiền. Mặt hộp có thể là mica hút nổi (sang, bền) hoặc bạt xuyên đèn (rẻ, dễ thay nội dung).

Cần khảo sát kết cấu tường và nguồn điện trước khi báo giá.', '/products/hop-den.svg', '["/products/hop-den.svg", "/products/hop-den-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Mặt hộp", "type": "radio", "required": true, "values": [{"value": "mica_hut_noi", "label": "Mica hút nổi"}, {"value": "bat_xuyen_den", "label": "Bạt xuyên đèn"}, {"value": "mica_in_uv", "label": "Mica in UV"}]}, {"key": "finishing", "label": "Số mặt", "type": "radio", "required": true, "values": [{"value": "1_mat", "label": "Một mặt (ốp tường)"}, {"value": "2_mat", "label": "Hai mặt (vuông góc mặt tiền)"}]}]'::jsonb, '5 – 10 ngày làm việc', 'Gửi ảnh mặt tiền chụp từ xa và từ gần, số đo rộng × cao × dày mong muốn, kèm file logo vector.', '[{"q": "Hộp đèn hai mặt có cần xin phép không?", "a": "Vì nhô ra vỉa hè nên thường cần, chúng tôi tư vấn kích thước phù hợp quy định địa phương."}]'::jsonb, true, false, false, null, 'bien-hieu', 'thi_cong', false, true, 18, 'Hộp đèn — giá và đặt in online | Nhà In Trẻ', 'Hộp đèn mica hoặc bạt xuyên đèn, một mặt hoặc hai mặt — treo vuông góc mặt tiền, nhìn thấy từ xa.'),
  ('thi-cong-mat-tien', 'TC-MT', 'Thi công mặt tiền', 'THI_CONG_MAT_TIEN', 'Trọn gói mặt tiền cửa hàng: biển, đèn, decal kính, chữ nổi — một đội làm hết, một hóa đơn.', 'Thay vì gọi ba nơi cho biển, decal và đèn, bạn giao trọn mặt tiền cho một đội. Chúng tôi đo, dựng bản vẽ mô phỏng trên ảnh thật, chốt giá một lần rồi thi công gọn trong 1 – 2 đêm để không ảnh hưởng buôn bán.

Đây là dịch vụ khảo sát bắt buộc — mỗi mặt tiền một kết cấu khác nhau.', '/products/thi-cong-mat-tien.svg', '["/products/thi-cong-mat-tien.svg", "/products/thi-cong-mat-tien-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[{"key": "material", "label": "Hạng mục cần làm", "type": "radio", "required": true, "values": [{"value": "tron_goi", "label": "Trọn gói mặt tiền"}, {"value": "bien_den", "label": "Biển + đèn"}, {"value": "kinh_decal", "label": "Kính + decal"}]}, {"key": "finishing", "label": "Thời gian thi công", "type": "radio", "required": false, "values": [{"value": "gio_hanh_chinh", "label": "Giờ hành chính"}, {"value": "ban_dem", "label": "Ban đêm (không ảnh hưởng bán hàng)"}]}]'::jsonb, 'Khảo sát trong 24h, thi công 7 – 14 ngày', 'Gửi ảnh chụp toàn bộ mặt tiền (đứng đối diện) và ảnh chụp hai bên, kèm địa chỉ để đội khảo sát tới đo.', '[{"q": "Có làm ngoài Hà Nội không?", "a": "Có, các tỉnh lân cận chúng tôi vẫn nhận, chi phí đi lại tính riêng và báo trước."}]'::jsonb, true, false, false, null, 'bien-hieu', 'thi_cong', false, true, 19, 'Thi công mặt tiền — giá và đặt in online | Nhà In Trẻ', 'Trọn gói mặt tiền cửa hàng: biển, đèn, decal kính, chữ nổi — một đội làm hết, một hóa đơn.'),
  ('san-pham-khac', 'KHAC', 'Sản phẩm khác', 'KHAC', 'Không thấy thứ bạn cần? Mô tả ý tưởng và gửi file — chúng tôi xem rồi báo giá.', 'Danh mục này dành cho những thứ không nằm gọn trong bảng giá: túi giấy, tem bảo hành, thiệp cưới, hộp đựng, in trên vật liệu lạ, hoặc một ý tưởng bạn chưa biết gọi tên là gì.

Bạn cứ mô tả và gửi ảnh tham khảo, chúng tôi trả lời trong giờ làm việc.', '/products/san-pham-khac.svg', '["/products/san-pham-khac.svg", "/products/san-pham-khac-2.svg"]'::jsonb, 'QUOTE_REQUIRED', null, null, '{}'::jsonb, '[]'::jsonb, 'Phản hồi trong 2 giờ làm việc', 'Gửi bất cứ thứ gì bạn có: ảnh chụp mẫu tham khảo, file thiết kế, hoặc chỉ một đoạn mô tả.', '[{"q": "Số lượng ít có nhận không?", "a": "Có. Chúng tôi nhận từ 1 sản phẩm, giá sẽ khác so với in số lượng lớn."}]'::jsonb, true, false, false, null, 'khac', 'in_an', false, true, 20, 'Sản phẩm khác — giá và đặt in online | Nhà In Trẻ', 'Không thấy thứ bạn cần? Mô tả ý tưởng và gửi file — chúng tôi xem rồi báo giá.')
on conflict (slug) do nothing;

