  ('brand', '{"name": "Nhà In Trẻ", "logoUrl": "", "faviconUrl": "", "slogan": "Có file thì tải lên, chưa có file thì chúng tôi hỗ trợ thiết kế.", "description": "Nhà in tại Hà Nội cho quán, cửa hàng và thương hiệu nhỏ. Nhận file online, báo giá nhanh, in đúng hẹn.", "phone": "0900000000", "zalo": "0900000000", "email": "lienhe@nhaintre.vn", "address": "Số 1 Cầu Diễn, Nam Từ Liêm, Hà Nội", "workingHours": "8:00 – 18:00, Thứ Hai – Thứ Bảy", "facebook": "", "tiktok": "", "instagram": ""}'::jsonb, 'Thông tin thương hiệu hiển thị trên website khách hàng'),
  ('theme', '{"primary": "#0057FF", "accent": "#EC008C", "background": "#FFFFFF", "foreground": "#101114", "fontHeading": "be-vietnam-pro", "fontBody": "be-vietnam-pro", "radius": "md", "shadow": "soft", "buttonStyle": "solid"}'::jsonb, 'Design token: màu, font, bo góc, shadow, kiểu nút'),
  ('home', '{"announcement": {"enabled": true, "text": "Đơn đặt trước 15h được in trong ngày. Nội thành Hà Nội giao trong 24h.", "linkUrl": "/san-pham", "linkText": "Xem bảng giá"}, "hero": {"enabled": true, "title": "Có file thì tải lên, chưa có file thì chúng tôi hỗ trợ thiết kế.", "description": "Chọn sản phẩm, nhập thông số, gửi file. Sản phẩm có giá sẵn thì thanh toán ngay bằng QR. Sản phẩm cần khảo sát thì bạn nhận báo giá trong 2 giờ làm việc.", "imageUrl": "/hero.svg", "ctaText": "Chọn sản phẩm in", "ctaUrl": "/san-pham", "ctaSecondaryText": "Tải file để báo giá", "ctaSecondaryUrl": "/gui-file-in"}, "categories": {"enabled": true}, "popular": {"enabled": true, "title": "Khách đặt nhiều nhất"}, "process": {"enabled": true, "title": "Đặt in mất bao lâu", "steps": [{"title": "Chọn sản phẩm", "description": "Chọn loại in và thông số. Giá hiện ngay nếu sản phẩm có bảng giá."}, {"title": "Gửi file", "description": "Kéo thả file vào trình duyệt. Chưa có file thì để lại yêu cầu thiết kế."}, {"title": "Chốt và thanh toán", "description": "Quét QR để trả sản phẩm có giá sẵn, hoặc chờ báo giá cho hạng mục cần khảo sát."}, {"title": "Nhận hàng", "description": "Nội thành Hà Nội giao trong 24h. Hạng mục thi công có đội tới lắp."}]}, "benefits": {"enabled": true, "title": "Vì sao khách quay lại", "items": [{"title": "Kiểm file trước khi in", "description": "Chúng tôi mở file ra xem trước. Sai kích thước, thiếu tràn lề hay ảnh vỡ, bạn biết trước khi mất tiền."}, {"title": "Báo giá trong 2 giờ", "description": "Trong giờ làm việc. Không để bạn chờ đến hôm sau mới biết hết bao nhiêu."}, {"title": "Không có file vẫn in được", "description": "Gửi ý tưởng và logo, đội thiết kế dựng mẫu cho bạn duyệt."}, {"title": "Giá hiện trước khi đặt", "description": "Sản phẩm phổ biến có bảng giá công khai, không cần nhắn tin hỏi."}]}, "shopServices": {"enabled": true, "title": "Dành cho quán và cửa hàng", "description": "Bộ nhận diện tối thiểu để mở cửa: biển, menu, tem, standee. Làm một lần, dùng cả năm."}, "combo": {"enabled": true, "title": "Combo khai trương", "description": "Đủ thứ cần có trong ngày mở cửa, đặt một lần cho gọn.", "items": [{"title": "Combo quán cà phê", "description": "Menu A3 cán màng, 100 tem dán ly, 1 standee cuốn, 200 danh thiếp.", "price": "1.290.000đ"}, {"title": "Combo cửa hàng", "description": "Biển alu chữ nổi 2m, decal kính mặt tiền, 500 tem sản phẩm.", "price": "Khảo sát rồi báo giá"}, {"title": "Combo thương hiệu nhỏ", "description": "1.000 tem nhựa sữa, 500 sticker bế hình, 500 danh thiếp giấy mỹ thuật.", "price": "1.890.000đ"}]}, "gallery": {"enabled": true, "title": "Mẫu thành phẩm"}, "testimonials": {"enabled": true, "title": "Khách nói gì", "items": [{"name": "Chị Linh", "role": "Chủ quán cà phê, Cầu Giấy", "content": "Gửi file lúc 10h, chiều có menu mang về. Bạn kiểm file báo mình thiếu tràn lề, sửa xong mới in nên không hỏng tờ nào."}, {"name": "Anh Tuấn", "role": "Cửa hàng điện thoại, Hà Đông", "content": "Biển alu và decal kính làm trong một đêm, sáng ra mở cửa bán bình thường. Giá chốt một lần, không phát sinh."}, {"name": "Chị Hà", "role": "Thương hiệu mỹ phẩm nhỏ", "content": "Đặt tem nhựa sữa trên web, quét QR trả tiền luôn, hai hôm sau có hàng. Không phải nhắn tin hỏi giá."}]}, "faq": {"enabled": true, "title": "Câu hỏi thường gặp", "items": [{"q": "Tôi chưa có file thiết kế thì có in được không?", "a": "Được. Bạn gửi ý tưởng, logo và nội dung, đội thiết kế dựng mẫu để bạn duyệt trước khi in. Phí thiết kế báo trước, không tính thêm sau."}, {"q": "Bao lâu thì có báo giá?", "a": "Trong 2 giờ làm việc với hạng mục xem file là báo được. Hạng mục cần khảo sát tại chỗ thì trong 24 giờ kể từ khi đo."}, {"q": "Thanh toán như thế nào?", "a": "Sản phẩm có giá sẵn thì quét QR chuyển khoản ngay trên web. Hạng mục thi công thì đặt cọc trước, phần còn lại thanh toán khi nghiệm thu."}, {"q": "File của tôi có bị dùng vào việc khác không?", "a": "Không. File nằm trong kho lưu trữ riêng, chỉ nhân viên phụ trách đơn của bạn mở được, và được xóa theo chính sách lưu trữ."}, {"q": "Giao hàng mất bao lâu?", "a": "Nội thành Hà Nội giao trong 24 giờ kể từ khi in xong. Tỉnh khác gửi qua nhà xe hoặc chuyển phát, 2 – 4 ngày."}]}, "finalCta": {"enabled": true, "title": "Gửi file, nhận giá, xong.", "description": "Không cần gọi điện hỏi giá. Tải file lên và chúng tôi trả lời trong 2 giờ làm việc.", "ctaText": "Gửi file in", "ctaUrl": "/gui-file-in"}}'::jsonb, 'Nội dung và bật/tắt từng section trang chủ'),
  ('payment', '{"mode": "vietqr_image", "bankBin": "", "bankName": "", "accountNumber": "", "accountName": "", "branch": "", "prefix": "NHAIN", "note": "Chuyển khoản đúng nội dung để đơn được ghi nhận tự động."}'::jsonb, 'Cấu hình QR ngân hàng. Để trống thì lấy giá trị từ biến môi trường.')
